import json
from datetime import datetime
from typing import List

import modal
from fastapi import FastAPI

IMAGE = modal.Image.debian_slim().pip_install("fastapi")

app = modal.App("modal-event-pipeline")

queue = modal.Queue.from_name("modal-event-pipeline-queue", create_if_missing=True)
volume = modal.Volume.from_name("modal-event-pipeline-vol", create_if_missing=True)
status_dict = modal.Dict.from_name("modal-event-pipeline-output", create_if_missing=True)

PROCESSED_EVENTS_PATH = "/events/processed_events.json"

fastapi_app = FastAPI()


@fastapi_app.get("/")
async def get_status():
    return {
        "events_produced": status_dict.get("events_produced"),
        "events_consumed": status_dict.get("events_consumed"),
        "processing_complete": status_dict.get("processing_complete"),
        "output_path": status_dict.get("output_path"),
    }


@app.function(image=IMAGE)
def produce_events() -> None:
    events = []
    for event_id in range(1, 11):
        events.append(
            {
                "event_id": event_id,
                "timestamp": datetime.utcnow().isoformat() + "Z",
                "payload": f"synthetic event payload {event_id}",
            }
        )

    for event in events:
        queue.put(event)


@app.function(image=IMAGE, volumes={"/events": volume})
def consume_events() -> List[dict]:
    processed_events: List[dict] = []
    while True:
        event = queue.get(timeout=1)
        if event is None:
            break
        payload = event.get("payload", "")
        processed = {
            **event,
            "processed": True,
            "word_count": len(payload.split()),
        }
        processed_events.append(processed)

    with open(PROCESSED_EVENTS_PATH, "w", encoding="utf-8") as file_handle:
        json.dump(processed_events, file_handle, indent=2)

    volume.commit()
    return processed_events


@app.function(image=IMAGE)
def update_status(events_produced: int, events_consumed: int) -> None:
    status_dict["events_produced"] = events_produced
    status_dict["events_consumed"] = events_consumed
    status_dict["processing_complete"] = "true"
    status_dict["output_path"] = PROCESSED_EVENTS_PATH


@app.function(image=IMAGE)
@modal.web_endpoint(method="GET")
async def status_endpoint():
    return await get_status()


@app.local_entrypoint()
def main() -> None:
    produce_events.remote()
    processed_events = consume_events.remote()
    update_status.remote(10, len(processed_events))

